import React, { useState, useEffect, useCallback, useRef } from 'react';
import { doubtAPI, slotAPI, authAPI } from '../services/api';
import io from 'socket.io-client';

const QueriesPage = () => {
  const [doubts, setDoubts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const socketRef = useRef(null);

  // States for replying internally
  const [replyText, setReplyText] = useState({});
  const [scheduleData, setScheduleData] = useState({});

  const fetchDoubts = useCallback(async () => {
    try {
      const response = await doubtAPI.getStaffDoubts();
      setDoubts(response.data.doubts || []);
      setError('');
    } catch (err) {
      setError('Failed to fetch queries.');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchDoubts();
  }, [fetchDoubts]);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: { token: sessionStorage.getItem('token') || localStorage.getItem('token') },
    });
    socketRef.current.on('doubt_updated', fetchDoubts);
    return () => {
      socketRef.current?.off('doubt_updated', fetchDoubts);
      socketRef.current?.disconnect();
    };
  }, [fetchDoubts]);

  const showSuccess = (msg) => {
    setSuccess(msg);
    setTimeout(() => setSuccess(''), 3000);
  };

  const showError = (msg) => {
    setError(msg);
    setTimeout(() => setError(''), 4000);
  };

  const handleReplyChange = (doubtId, text) => {
    setReplyText((prev) => ({ ...prev, [doubtId]: text }));
  };

  const handleScheduleChange = (doubtId, field, value) => {
    setScheduleData((prev) => ({
      ...prev,
      [doubtId]: { ...prev[doubtId], [field]: value },
    }));
  };

  const submitReply = async (doubtId) => {
    const text = replyText[doubtId];
    if (!text?.trim()) {
      showError('Reply text cannot be empty.');
      return;
    }
    try {
      await doubtAPI.updateDoubtStatus(doubtId, { status: 'Resolved', reply: text });
      setReplyText((prev) => ({ ...prev, [doubtId]: '' }));
      showSuccess('Reply sent successfully.');
      fetchDoubts();
    } catch (err) {
      showError('Failed to send reply.');
    }
  };

  const submitSchedule = async (doubtId) => {
    const data = scheduleData[doubtId] || {};
    if (!data.date || !data.time) {
      showError('Please select date and time to schedule.');
      return;
    }
    try {
      await slotAPI.createSlotForDoubt({
        doubtId: doubtId,
        date: data.date,
        time: data.time,
        duration: data.duration || 30,
        topic: 'Doubt Resolution Session',
        notes: data.notes || '',
      });
      setScheduleData((prev) => ({ ...prev, [doubtId]: {} }));
      showSuccess('Slot scheduled successfully.');
      fetchDoubts();
    } catch (err) {
      showError(err.response?.data?.error || 'Failed to schedule slot.');
    }
  };

  return (
    <>
      <div className="animated-bg">
        <div className="blob blob-1"></div>
        <div className="blob blob-2"></div>
        <div className="blob blob-3"></div>
      </div>
      <div className="page-content" style={{ maxWidth: '900px', margin: '0 auto', paddingTop: '2rem' }}>
        <h2 className="dashboard-title">Student Queries</h2>
        <p className="dashboard-subtitle">Reply to doubts directly or schedule live sessions.</p>

        {error && (
          <div style={{ background: 'rgba(239, 68, 68, 0.2)', padding: '1rem', borderRadius: '8px', marginBottom: '1rem', color: '#fff' }}>
            {error}
          </div>
        )}
        {success && (
          <div style={{ background: 'rgba(34, 197, 94, 0.2)', padding: '1rem', borderRadius: '8px', marginBottom: '1rem', color: '#fff' }}>
            {success}
          </div>
        )}

        {loading ? (
          <div className="island-card">Loading queries...</div>
        ) : doubts.length === 0 ? (
          <div className="island-card">No queries assigned to you.</div>
        ) : (
          doubts.map((doubt) => (
            <div key={doubt._id} className="island-card" style={{ marginBottom: '1.5rem', textAlign: 'left' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '1rem', marginBottom: '1rem' }}>
                <div>
                  <h3 style={{ margin: '0 0 0.5rem 0' }}>{doubt.subject}</h3>
                  <p style={{ margin: 0, color: 'var(--text-muted)' }}>
                    From: {doubt.studentId?.name || 'Unknown Student'}
                  </p>
                </div>
                <span style={{ 
                  background: doubt.status === 'Resolved' ? 'var(--status-success)' : 'var(--accent-primary)',
                   padding: '4px 12px', borderRadius: '12px', fontSize: '0.85rem' 
                }}>
                  {doubt.status}
                </span>
              </div>

              <div style={{ marginBottom: '1.5rem' }}>
                <p><strong>Question:</strong> {doubt.question}</p>
                {doubt.reply && (
                   <div style={{ padding: '1rem', background: 'rgba(var(--accent-primary-rgb), 0.1)', borderRadius: '8px', borderLeft: '4px solid var(--accent-primary)' }}>
                     <strong>Your Reply:</strong> <p style={{ margin: 0 }}>{doubt.reply}</p>
                   </div>
                )}
                {doubt.requestSlot && doubt.status !== 'Slot Scheduled' && (
                  <p style={{ color: 'var(--status-warning)', fontSize: '0.9rem', marginTop: '0.5rem' }}>
                    * The student has requested a live slot for this query.
                  </p>
                )}
              </div>

              {/* Action Area */}
              {doubt.status !== 'Resolved' && doubt.status !== 'Slot Scheduled' && (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>

                  {/* Quick Reply Form */}
                  <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '8px' }}>
                    <h4 style={{ margin: '0 0 0.5rem 0' }}>Quick Reply</h4>
                    <textarea 
                      className="form-input" 
                      rows="3" 
                      style={{ width: '100%', marginBottom: '0.5rem' }}
                      placeholder="Type your answer here..."
                      value={replyText[doubt._id] || ''}
                      onChange={(e) => handleReplyChange(doubt._id, e.target.value)}
                    />
                    <button className="btn btn-primary" onClick={() => submitReply(doubt._id)}>
                      Send Reply
                    </button>
                  </div>

                  {/* Schedule Slot Form */}
                  <div style={{ background: 'rgba(255,255,255,0.03)', padding: '1rem', borderRadius: '8px' }}>
                    <h4 style={{ margin: '0 0 0.5rem 0' }}>Or Schedule a Live Session</h4>
                    <div style={{ display: 'flex', gap: '1rem', flexWrap: 'wrap', marginBottom: '0.5rem' }}>
                      <input 
                        type="date" 
                        className="form-input"
                        value={scheduleData[doubt._id]?.date || ''}
                        onChange={(e) => handleScheduleChange(doubt._id, 'date', e.target.value)}
                      />
                      <input 
                        type="time" 
                        className="form-input"
                        value={scheduleData[doubt._id]?.time || ''}
                        onChange={(e) => handleScheduleChange(doubt._id, 'time', e.target.value)}
                      />
                      <select 
                        className="form-input"
                        value={scheduleData[doubt._id]?.duration || 30}
                        onChange={(e) => handleScheduleChange(doubt._id, 'duration', e.target.value)}
                      >
                        <option value={15}>15 mins</option>
                        <option value={30}>30 mins</option>
                        <option value={60}>60 mins</option>
                      </select>
                    </div>
                    <button className="btn btn-primary" style={{ background: 'transparent', border: '1px solid var(--accent-primary)', color: 'var(--accent-primary)' }} onClick={() => submitSchedule(doubt._id)}>
                      Schedule Session
                    </button>
                  </div>

                </div>
              )}
            </div>
          ))
        )}
      </div>
    </>
  );
};

